import{_ as o,o as e,c as a,ai as i}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"03 模型选择指南：按环境与使用场景选型","description":"","frontmatter":{},"headers":[],"relativePath":"ai/model-deploy/03-model-selection.md","filePath":"ai/model-deploy/03-model-selection.md"}'),r={name:"ai/model-deploy/03-model-selection.md"};function t(n,l,s,d,c,g){return e(),a("div",null,[...l[0]||(l[0]=[i('<h1 id="_03-模型选择指南-按环境与使用场景选型" tabindex="-1">03 模型选择指南：按环境与使用场景选型 <a class="header-anchor" href="#_03-模型选择指南-按环境与使用场景选型" aria-label="Permalink to “03 模型选择指南：按环境与使用场景选型”">​</a></h1><blockquote><p>目标：你能在不同环境下（本地/云端/混合），按任务（写代码/写文档/RAG/Agent）选到“够用且稳定”的模型，并且知道 <strong>2026 当下优先用哪些模型</strong>（不追新、不踩坑）。</p></blockquote><blockquote><p>注：模型更新很快，这篇给的是 <strong>“优先级 + 可落地候选清单”</strong>。你只要在同一梯队里换成你能用的提供方即可。</p></blockquote><h2 id="_1-先定-3-个变量-不定这三个-选型一定乱" tabindex="-1">1）先定 3 个变量（不定这三个，选型一定乱） <a class="header-anchor" href="#_1-先定-3-个变量-不定这三个-选型一定乱" aria-label="Permalink to “1）先定 3 个变量（不定这三个，选型一定乱）”">​</a></h2><ul><li><strong>环境</strong>：本地 / 云端 / 混合</li><li><strong>任务</strong>：代码、文档写作、问答、RAG、Agent 多步任务</li><li><strong>约束</strong>：隐私、预算、延迟、上下文长度</li></ul><h2 id="_1-1-一张-先选环境-再选模型-的决策树-最少纠结版" tabindex="-1">1.1 一张“先选环境，再选模型”的决策树（最少纠结版） <a class="header-anchor" href="#_1-1-一张-先选环境-再选模型-的决策树-最少纠结版" aria-label="Permalink to “1.1 一张“先选环境，再选模型”的决策树（最少纠结版）”">​</a></h2><ul><li><strong>必须本地（隐私/离线）？</strong><ul><li><strong>是</strong>：优先选 <strong>Qwen（中文强）/ Llama（通用强）/ DeepSeek（推理/代码常见）</strong> 的中小尺寸，先跑通。</li><li><strong>否</strong>：优先走云端（稳定、长上下文、能力更强）。</li></ul></li><li><strong>是否要做 Agent（工具调用/结构化输出）？</strong><ul><li><strong>是</strong>：优先选“工具调用稳定/格式稳定”的强模型（云端更省心），本地则优先选对齐更好的通用模型，不要上太小的“玩具模型”。</li></ul></li><li><strong>是否要做 RAG？</strong><ul><li><strong>是</strong>：选型重点是 <strong>上下文窗口 + 稳定性</strong>；不要指望“大模型自己检索”。</li></ul></li></ul><h2 id="_2-按环境的选型策略" tabindex="-1">2）按环境的选型策略 <a class="header-anchor" href="#_2-按环境的选型策略" aria-label="Permalink to “2）按环境的选型策略”">​</a></h2><h3 id="_2-1-本地-优先-能跑-稳定" tabindex="-1">2.1 本地（优先“能跑 + 稳定”） <a class="header-anchor" href="#_2-1-本地-优先-能跑-稳定" aria-label="Permalink to “2.1 本地（优先“能跑 + 稳定”）”">​</a></h3><p>适合：</p><ul><li>笔记总结、面试题生成、轻量问答</li></ul><p>建议策略：</p><ul><li>先选“中小参数”模型跑通，再逐步上更强模型</li><li>若你要做 RAG：优先看上下文与速度是否可接受</li></ul><p>不建议本地硬扛：</p><ul><li>超长文档一次性输入</li><li>复杂多步推理（成本/时间会很高）</li></ul><h4 id="_2-1-1-2026-本地优先候选-按-好用-通用-中文" tabindex="-1">2.1.1 2026 本地优先候选（按“好用/通用/中文”） <a class="header-anchor" href="#_2-1-1-2026-本地优先候选-按-好用-通用-中文" aria-label="Permalink to “2.1.1 2026 本地优先候选（按“好用/通用/中文”）”">​</a></h4><ul><li><strong>通用 + 生态成熟</strong>：<code>Llama 3.x</code>（同梯队任选你能下载/能跑的版本）</li><li><strong>中文/工程落地友好</strong>：<code>Qwen2.x / Qwen2.5</code>（中文与工具类任务常见）</li><li><strong>代码/推理常见候选</strong>：<code>DeepSeek</code> 系列（常见于“写代码/推理/成本”权衡）</li><li><strong>低资源尝鲜</strong>：<code>Phi</code>、<code>Mistral 7B</code> 等小模型（适合“草稿/结构化提取”，不建议承担关键推理）</li></ul><blockquote><p>选本地模型的要点：<strong>先选中等尺寸跑通闭环，再决定要不要上更大尺寸</strong>。你后面真正提效，更多来自“Prompt/工具链/RAG”，而不是盲目换更大的模型。</p></blockquote><h3 id="_2-2-云端-优先-质量-长上下文-稳定" tabindex="-1">2.2 云端（优先“质量 + 长上下文 + 稳定”） <a class="header-anchor" href="#_2-2-云端-优先-质量-长上下文-稳定" aria-label="Permalink to “2.2 云端（优先“质量 + 长上下文 + 稳定”）”">​</a></h3><p>适合：</p><ul><li>复杂代码生成/重构</li><li>长文档总结/对比</li><li>高质量面试回答打磨</li></ul><p>建议策略：</p><ul><li>把“高价值任务”放到云端强模型</li><li>把“批量、重复、低价值任务”留给本地/小模型</li></ul><h4 id="_2-2-1-2026-云端优先候选-按能力梯队" tabindex="-1">2.2.1 2026 云端优先候选（按能力梯队） <a class="header-anchor" href="#_2-2-1-2026-云端优先候选-按能力梯队" aria-label="Permalink to “2.2.1 2026 云端优先候选（按能力梯队）”">​</a></h4><ul><li><strong>高质量通用（代码/写作/多模态都强）</strong>：<code>GPT-4o</code>（同梯队的最新/可用版本优先）</li><li><strong>长文本/写作/对齐稳定</strong>：<code>Claude 3.x</code>（适合“长文档对比/高质量润色/严谨表达”）</li><li><strong>中文/性价比/国内可用性</strong>：<code>Qwen（通义）</code> 系列云端模型（适合“中文业务/成本敏感/落地快”）</li><li><strong>代码向/性价比</strong>：<code>DeepSeek</code> 系列云端模型（常见于“代码 + 成本”权衡）</li></ul><blockquote><p>云端选型口诀：<strong>关键任务上强模型，批量任务用性价比模型</strong>。把“路由策略”写进你的 <code>LLM Gateway</code>，长期收益最大。</p></blockquote><h3 id="_2-3-混合-推荐" tabindex="-1">2.3 混合（推荐） <a class="header-anchor" href="#_2-3-混合-推荐" aria-label="Permalink to “2.3 混合（推荐）”">​</a></h3><p>一个简单可落地的分工：</p><ul><li><strong>本地模型</strong>：草稿、批量总结、结构化提取、离线使用</li><li><strong>云端强模型</strong>：最终润色、关键回答、复杂规划与推理</li></ul><h4 id="_2-3-1-混合的最小落地组合-你可以直接照抄" tabindex="-1">2.3.1 混合的最小落地组合（你可以直接照抄） <a class="header-anchor" href="#_2-3-1-混合的最小落地组合-你可以直接照抄" aria-label="Permalink to “2.3.1 混合的最小落地组合（你可以直接照抄）”">​</a></h4><ul><li><strong>本地</strong>：<code>Qwen2.5（中小尺寸）</code> 或 <code>Llama 3.x（中小尺寸）</code>（做草稿/批量/离线）</li><li><strong>云端</strong>：<code>GPT-4o</code> 或 <code>Claude 3.x</code>（做最终润色/关键推理/长文档）</li><li><strong>路由规则</strong>（最实用）： <ul><li>“写简历/重要答复/复杂重构” → 云端强模型</li><li>“批量出题/结构化提取/生成初稿” → 本地/性价比云端</li></ul></li></ul><h2 id="_3-按使用场景给出-选型建议" tabindex="-1">3）按使用场景给出“选型建议” <a class="header-anchor" href="#_3-按使用场景给出-选型建议" aria-label="Permalink to “3）按使用场景给出“选型建议””">​</a></h2><h3 id="_3-1-日常开发提效-写代码-解释报错" tabindex="-1">3.1 日常开发提效（写代码/解释报错） <a class="header-anchor" href="#_3-1-日常开发提效-写代码-解释报错" aria-label="Permalink to “3.1 日常开发提效（写代码/解释报错）”">​</a></h3><ul><li><strong>优先级</strong>：代码能力 &gt; 稳定性 &gt; 成本</li><li><strong>建议</strong>： <ul><li>云端强模型用于关键任务（重构、复杂问题）</li><li>本地模型用于快速问答、模板生成</li></ul></li></ul><p><strong>当下建议：</strong></p><ul><li><strong>云端首选</strong>：<code>GPT-4o</code> / <code>Claude 3.x</code>（关键任务）</li><li><strong>本地首选</strong>：<code>DeepSeek（代码向）</code> / <code>Qwen2.5</code> / <code>Llama 3.x</code>（日常与离线）</li></ul><h3 id="_3-2-文档写作-知识库-简历-面试稿" tabindex="-1">3.2 文档写作（知识库/简历/面试稿） <a class="header-anchor" href="#_3-2-文档写作-知识库-简历-面试稿" aria-label="Permalink to “3.2 文档写作（知识库/简历/面试稿）”">​</a></h3><ul><li><strong>优先级</strong>：表达质量 &gt; 结构化输出能力 &gt; 稳定性</li><li><strong>建议</strong>： <ul><li>先用本地模型出结构（目录/要点）</li><li>再用云端强模型做润色与统一口径</li></ul></li></ul><p><strong>当下建议：</strong></p><ul><li><strong>云端首选</strong>：<code>Claude 3.x</code>（长文档/表达一致性）+ <code>GPT-4o</code>（综合能力）</li><li><strong>本地首选</strong>：<code>Qwen2.5</code>（中文写作/结构化输出）或 <code>Llama 3.x</code></li></ul><h3 id="_3-3-rag-知识库问答" tabindex="-1">3.3 RAG（知识库问答） <a class="header-anchor" href="#_3-3-rag-知识库问答" aria-label="Permalink to “3.3 RAG（知识库问答）”">​</a></h3><ul><li><strong>优先级</strong>：上下文长度 + 稳定性 &gt; 纯模型参数大小</li><li><strong>建议</strong>： <ul><li>不要把“检索”交给模型：检索交给你的系统（向量库/索引）</li><li>模型只负责“基于检索片段回答”</li></ul></li></ul><p><strong>当下建议：</strong></p><ul><li><strong>云端</strong>：<code>GPT-4o</code> / <code>Claude 3.x</code>（回答质量更稳）</li><li><strong>本地</strong>：<code>Qwen2.5</code> / <code>Llama 3.x</code>（配合检索片段足够好用）</li></ul><blockquote><p>RAG 的核心不是“换更大模型”，而是：切块、召回、重排、引用与拒答策略。</p></blockquote><h3 id="_3-4-agent-工具调用、多步任务" tabindex="-1">3.4 Agent（工具调用、多步任务） <a class="header-anchor" href="#_3-4-agent-工具调用、多步任务" aria-label="Permalink to “3.4 Agent（工具调用、多步任务）”">​</a></h3><ul><li><strong>优先级</strong>：稳定性（格式/函数调用） &gt; 推理能力 &gt; 成本</li><li><strong>建议</strong>： <ul><li>关键点是“结构化输出/工具调用”能力稳定</li><li>给 Agent 加：输出校验、重试、幂等、日志</li></ul></li></ul><p><strong>当下建议：</strong></p><ul><li><strong>云端优先</strong>：<code>GPT-4o</code> / <code>Claude 3.x</code>（工具调用与格式更稳定）</li><li><strong>本地备选</strong>：<code>Qwen2.5</code> / <code>Llama 3.x</code>（务必加“输出校验 + 重试”）</li></ul><h2 id="_4-你可以直接照抄的落地方案-最少折腾版" tabindex="-1">4）你可以直接照抄的落地方案（最少折腾版） <a class="header-anchor" href="#_4-你可以直接照抄的落地方案-最少折腾版" aria-label="Permalink to “4）你可以直接照抄的落地方案（最少折腾版）”">​</a></h2><ul><li><strong>第一版</strong>：云端 API 作为主力 + 本地小模型做离线/批量</li><li><strong>第二版</strong>：加一个 LLM Gateway（统一切换、统一日志与重试）</li><li><strong>第三版</strong>：关键链路再做自建推理与成本优化</li></ul><h2 id="_5-我给你的-当前优先推荐-按你这个知识库-agent-学习路线" tabindex="-1">5）我给你的“当前优先推荐”（按你这个知识库/Agent 学习路线） <a class="header-anchor" href="#_5-我给你的-当前优先推荐-按你这个知识库-agent-学习路线" aria-label="Permalink to “5）我给你的“当前优先推荐”（按你这个知识库/Agent 学习路线）”">​</a></h2><ul><li><strong>你现在最该先配的两套：</strong><ul><li><strong>本地（离线/隐私/批量）</strong>：<code>Qwen2.5</code>（中小尺寸）或 <code>Llama 3.x</code>（中小尺寸）</li><li><strong>云端（关键质量/长文档/复杂推理）</strong>：<code>GPT-4o</code> 或 <code>Claude 3.x</code></li></ul></li><li><strong>如果你只想选一个最省心的</strong>： <ul><li><strong>纯云端</strong>：优先 <code>GPT-4o</code>（综合能力）或 <code>Claude 3.x</code>（长文档/写作）</li><li><strong>纯本地</strong>：优先 <code>Qwen2.5</code>（中文/工具型任务常见）或 <code>Llama 3.x</code>（通用能力/生态）</li></ul></li></ul>',53)])])}const _=o(r,[["render",t]]);export{u as __pageData,_ as default};
